<?php require __DIR__.'/bootstrap.php'; require_admin(); if($_SERVER['REQUEST_METHOD']!=='POST') out(['ok'=>false,'error'=>'Method not allowed'],405); if(empty($_FILES['file'])) out(['ok'=>false,'error'=>'Missing file'],400); $allowed=['image/jpeg','image/png','image/webp','image/gif','application/pdf']; if(!in_array($_FILES['file']['type'],$allowed,true)) out(['ok'=>false,'error'=>'Unsupported file type'],400); $dir=__DIR__.'/../assets/uploads'; if(!is_dir($dir)) mkdir($dir,0755,true); $name=time().'-'.preg_replace('/[^a-zA-Z0-9._-]/','-',$_FILES['file']['name']); $path=$dir.'/'.$name; if(!move_uploaded_file($_FILES['file']['tmp_name'],$path)) out(['ok'=>false,'error'=>'Upload failed'],500); out(['ok'=>true,'path'=>'/assets/uploads/'.$name]);
